import{_ as s,o as r,c as e,ag as t}from"./chunks/framework.WmBmIPw-.js";const _=JSON.parse('{"title":"变邻域搜索（Variable Neighborhood Search, VNS）","description":"","frontmatter":{},"headers":[],"relativePath":"or-opt/vns.md","filePath":"or-opt/vns.md","lastUpdated":1777122027000}'),o={name:"or-opt/vns.md"};function h(n,a,i,l,p,k){return r(),e("div",null,[...a[0]||(a[0]=[t('<h1 id="变邻域搜索-variable-neighborhood-search-vns" tabindex="-1">变邻域搜索（Variable Neighborhood Search, VNS） <a class="header-anchor" href="#变邻域搜索-variable-neighborhood-search-vns" aria-label="Permalink to &quot;变邻域搜索（Variable Neighborhood Search, VNS）&quot;">​</a></h1><p>变邻域搜索由 Mladenović 与 Hansen 等系统化提出：在单点搜索框架下，预备一组由弱到强（或由近到远）的邻域结构，在局部最优处通过「换邻域」或「抖动 + 再局部搜索」跳出当前吸引域。与固定单邻域的下降法相比，显式利用多邻域的互补性，属单解、基于邻域的元启发式，见 <a href="./metaheuristics.html">元启发式总览</a>。</p><p><strong>适用</strong>：组合优化（路径、调度、划分等）与部分连续问题在能定义多个邻域算子且每步评价 f 可承受时；邻域设计对效果起决定作用。</p><p><strong>核心</strong>：最外层是「设邻域下标 k → 抖 → 局部搜 → 按结果改 k/当前解」的循环，框图在第二节「基本 VNS 主循环」。全页叙述顺序为：主循环 → 抖动 → 变邻域下降（VND），主循环中第 3 步、第 4 步的机理分别在第三、四节展开。</p><hr><h2 id="记号与邻域结构" tabindex="-1">记号与邻域结构 <a class="header-anchor" href="#记号与邻域结构" aria-label="Permalink to &quot;记号与邻域结构&quot;">​</a></h2><p>设目标 f(s) 最小化，s 为可行解。给定有限个邻域映射 N_k，k∈{1,…,K_max}，通常按「步幅」或「破坏程度」单调：N_1 最局部，N_Kmax 扰动最大。对点 s，N_k(s) 表示经第 k 类算子一步可达的邻域点集（实现上常从 N_k(s) 中采样或枚举子集）。主循环里 k 同时参与「第 3 步抖动的步幅」与「内层 VND 里邻域的编号」，二者符号一致时叙述最顺。</p><hr><h2 id="基本-vns-主循环-最小化示意" tabindex="-1">基本 VNS 主循环（最小化示意） <a class="header-anchor" href="#基本-vns-主循环-最小化示意" aria-label="Permalink to &quot;基本 VNS 主循环（最小化示意）&quot;">​</a></h2><p>先给出最外层在做什么。下框只保留接口级步骤；第 3 步「抖动」、第 4 步「局部搜索」的约定，分别在再下两节「抖动（Shaking）」与「变邻域下降（VND）」中展开。</p><div class="custom-block algorithm"><p class="custom-block-title">▶ 基本 VNS（单解、多邻域 + 抖动）</p><h3 id="_1-初始化" tabindex="-1">1. 初始化 <a class="header-anchor" href="#_1-初始化" aria-label="Permalink to &quot;1. 初始化&quot;">​</a></h3><p>生成初始解 s，记历史最优 s⋆ ← s。设邻域族 N_1,…,N_K 与最大抖动强度 K_max。内层局搜的默认体例在第四节给出。</p><h3 id="_2-外层邻域下标" tabindex="-1">2. 外层邻域下标 <a class="header-anchor" href="#_2-外层邻域下标" aria-label="Permalink to &quot;2. 外层邻域下标&quot;">​</a></h3><p>设 k ← 1，表示本回合抖动使用的邻域级别。</p><h3 id="_3-抖动" tabindex="-1">3. 抖动 <a class="header-anchor" href="#_3-抖动" aria-label="Permalink to &quot;3. 抖动&quot;">​</a></h3><p>在 N_k 上自 s 依随机规则得新起点 s′（含义、与 k 的关系、如何生成 s′，见下节「抖动（Shaking）」）。</p><h3 id="_4-局部搜索" tabindex="-1">4. 局部搜索 <a class="header-anchor" href="#_4-局部搜索" aria-label="Permalink to &quot;4. 局部搜索&quot;">​</a></h3><p>以 s′ 为起点在全部或部分邻域上下降，直至得到局部最优点 s″；VND 是常用实现，见下下节「变邻域下降（VND）」；也可换用其他多邻域或单邻域下降。</p><h3 id="_5-接受与邻域级更新" tabindex="-1">5. 接受与邻域级更新 <a class="header-anchor" href="#_5-接受与邻域级更新" aria-label="Permalink to &quot;5. 接受与邻域级更新&quot;">​</a></h3><p>若 f(s″)&lt;f(s)，令 s ← s″，k ← 1，若 f(s″)&lt;f(s⋆) 则 s⋆ ← s″；否则 k ← k+1。若 k&gt;K_max，可 k ← 1 并配合全局迭代上限或 s ← s″ 的变体，依实现定稿。</p><h3 id="_6-终止" tabindex="-1">6. 终止 <a class="header-anchor" href="#_6-终止" aria-label="Permalink to &quot;6. 终止&quot;">​</a></h3><p>达时间、总评价次数、连续无改进步数等，输出 s⋆。</p></div><hr><h2 id="抖动-shaking" tabindex="-1">抖动（Shaking） <a class="header-anchor" href="#抖动-shaking" aria-label="Permalink to &quot;抖动（Shaking）&quot;">​</a></h2><p>本节的展开与第二节主循环中的第 3 步一一对应。</p><p><strong>作用</strong>：当当前 s 在某一局部搜索下已是局优时，若只在同一套确定性邻域里下降，会反复落回同一片吸引域。抖动的目标不是让单步 f 变小，而是利用随机性从 N_k(s) 里取新起点 s′，使随后主循环第 4 步的局部搜索有机会进入新的谷地。s′ 可以明显劣于 s，也无需在 N_k 上对 f 做任何最优化；这与第四节 VND 框在 N_k 内「找改进步」的取向相反。</p><p><strong>与邻域下标 k 的关系</strong>：k 标定「这一次抖动用哪一级邻域算子/步幅」。常令 k 自 1 递增至 K_max。k 较小时，一步只离开 s 的邻近位置，多在同一盆地内换起点；k 较大时，一步跨越更远、更易破坏当前结构，因而更常配合修复算子，并依赖内层主循环第 4 步的 VND/下降把 s′ 收敛到新的局优。</p><p><strong>从 N_k(s) 中生成 s′ 的常见方式</strong>（实现上可择一或组合）：</p><ul><li>一步随机邻居：在 N_k(s) 的枚举/候选集合中等概率或加权抽一点。</li><li>多步随机游走：对固定 k 连续做 t 次「在 N_k 中抽随机邻步并前进一步」，t 可常数、与 k 成比例或上界内均匀随机，相当于用同一 N_k 工具堆出更强扰动而不另建一套邻域结构。</li><li>逆移与有偏：若仅防「立刻逆回上一步」即可减轻短循环，可与极轻量禁忌同用；若引入复杂记忆则更接近混合 TS，已超出「纯 VNS 抖动」的朴素表述，实现时需单独定稿。</li></ul><p><strong>可行性与修复</strong>：N_k 可能产生不可行 s′ 时，可丢弃后重试、在 N_k 上有限次重采样，或调问题相关修复把 s′ 投回可行集；再进入局部搜索。哪一级邻域易不可行、修复代价多大，是邻域设计的一部分。</p><p><strong>何时加大 k</strong>：主循环第 5 步若多次记录「s″ 不优于当前 s」，则把 k 加一，使下一次抖动在更大范围内抽 s′。语义上等价于小抖不动就换强抖，而不同于把每次搜索都变成全局大随机重启；层次化的 k 是基本 VNS 与「单次大扰动再搜」的常用分野。</p><p><strong>与内层局搜的分工</strong>：抖动只负责「把我扔到哪儿去」，内层主循环第 4 步负责「在新起点上尽量爬到局部最优」。重复「抖—搜」在随机性上比单邻域里串很长一串随机可接受非改进步更短、也更容易控计算量，因为坏起点不必沿轨迹一路滚下去，可立即进入下一轮主循环第 5 步对 k 与 s 的更新。</p><hr><h2 id="变邻域下降-vnd" tabindex="-1">变邻域下降（VND） <a class="header-anchor" href="#变邻域下降-vnd" aria-label="Permalink to &quot;变邻域下降（VND）&quot;">​</a></h2><p><strong>定位</strong>：主循环第 4 步「局部搜索」常采用下框的 VND。在同一套多邻域 N_1,…,N_K 上做无随机抖动的、确定性从细到粗切换，直到各邻域上均为局优。VND 只做局部最优传递；实现时建议把「外层控制抖动的下标」与「内层 VND 在邻域族上的下标」在变量名或注释上区分开，免与第二节主循环的 k 混淆。</p><p>VND 仍可能停在多邻域意义下的强局优，不能替代主循环第 3 步的抖动；要跳出须回到最外层、在更大扰动上换起点。</p><p>当 VND 被基本 VNS 调用时，下框的初始 s 取自主循环第 3 步得到的抖动点；框内所得终点即主循环第 4 步返回的 s″。</p><div class="custom-block algorithm"><p class="custom-block-title">▶ 变邻域下降 VND</p><h3 id="_1-初始化-1" tabindex="-1">1. 初始化 <a class="header-anchor" href="#_1-初始化-1" aria-label="Permalink to &quot;1. 初始化&quot;">​</a></h3><p>选定可行解 s，设 k ← 1。</p><h3 id="_2-在当前邻域内找改进" tabindex="-1">2. 在当前邻域内找改进 <a class="header-anchor" href="#_2-在当前邻域内找改进" aria-label="Permalink to &quot;2. 在当前邻域内找改进&quot;">​</a></h3><p>在 N_k(s) 中寻找使 f 下降的点 s′（依「首次改进」「最速下降」等规则，直到 N_k 内对 s 为局部最优）。</p><h3 id="_3-邻域切换" tabindex="-1">3. 邻域切换 <a class="header-anchor" href="#_3-邻域切换" aria-label="Permalink to &quot;3. 邻域切换&quot;">​</a></h3><p>若找到改进 s′，令 s ← s′，k ← 1（回到最细邻域继续）；若 N_k 内无改进，令 k ← k+1。</p><h3 id="_4-终止" tabindex="-1">4. 终止 <a class="header-anchor" href="#_4-终止" aria-label="Permalink to &quot;4. 终止&quot;">​</a></h3><p>若 k&gt;K（所有 N_k 对当前 s 均局部最优），停，输出 s；否则回到步骤 2。</p></div><hr><h2 id="关键要素" tabindex="-1">关键要素 <a class="header-anchor" href="#关键要素" aria-label="Permalink to &quot;关键要素&quot;">​</a></h2><p><strong>邻域族顺序</strong>：k 小对应小扰动、利于微调；k 大利于跳出，但过强抖动易损可行或需修复算子。实践上常问题特化设计多种 2-opt、insert、swapping、大规模破坏—修复等，并在 N_k 间保持可实现的评价代价。与抖动强度、与 VND 内层的关系见上文两节。</p><p><strong>与禁忌搜索、模拟退火</strong>：VNS 用「多邻域结构 + 显式改变搜索邻域/抖动范围」管理探索，不必依赖禁忌表或温度；也可与 TS/SA 混合为同一内层或外层。</p><p><strong>扩展</strong>：如简化 VNS（reduced VNS）限制抖动与搜索子集、并行 VNS、及在全局框架中与精确子程序、大规模邻域搜索衔接，均属实现与文献变体，本页不逐条列参。</p>',32)])])}const c=s(o,[["render",h]]);export{_ as __pageData,c as default};
